form:Form.form:Scripts:
		function BACK_VALIDATE()
{
  if(Ctrl('MAIN_GRID').TotalRowsCount() == 0)
	{
		alert("El sujeto debe tener al menos una clasificación, cargue una y luego presione volver");
		return false;
	}

		var cantV=0;

		for(var i=0;i<Ctrl('MAIN_GRID').TotalRowsCount();i++)
			{          

			if(Ctrl('MAIN_GRID').GetCellXValue('oi_clasif_suj',i)=='')
				{

				cantV++;
				}			
			}

		if(cantV==Ctrl('MAIN_GRID').TotalRowsCount())
			{

			  alert("El sujeto debe tener al menos una clasificación, cargue una y luego presione volver");
				return false;
			}		

return true;
}
